+        if record.state != StakeState::UnderAppeal {
+            return Err(StakingError::new(
+                ERR_STAKE_INVALID_TRANSITION,
+                format!(
+                    "cannot resolve appeal: stake {} is in {} state, expected UnderAppeal",
+                    stake_id, record.state
+                ),
+            ));
+        }
